139→/**
140→ * 用隐藏窗口加载抖音视频页面，注入 JS 提取视频数据
141→ */
142→async function extractDouyinData(url) {
143→    return new Promise((resolve, reject) => {
144→        const win = new BrowserWindow({
145→            width: 800, height: 600,
146→            show: false,
147→            webPreferences: { nodeIntegration: false, contextIsolation: true }
148→        });
149→
150→        const timeout = setTimeout(() => {
151→            win.destroy();
152→            reject(new Error('抖音页面加载超时'));
153→        }, 20000);
154→
155→        win.webContents.on('did-finish-load', () => {
156→            setTimeout(async () => {
157→                try {
158→                    const data = await win.webContents.executeJavaScript(`
159→                        (function() {
160→                            try {
161→                                // 方法1: __UNIVERSAL_DATA_FOR_REHYDRATION__
162→                                var el = document.getElementById('RENDER_DATA');
163→                                if (el) {
164→                                    var decoded = decodeURIComponent(el.textContent);
165→                                    return { method: 'RENDER_DATA', data: decoded };
166→                                }
167→
168→                                // 方法2: RENDER_DATA 不存在时尝试 SSR_HYDRATED_DATA
169→                                var scripts = document.querySelectorAll('script');
170→                                for (var i = 0; i < scripts.length; i++) {
171→                                    var text = scripts[i].textContent || '';
172→                                    if (text.includes('window._SSR_HYDRATED_DATA')) {
173→                                        var match = text.match(/window\\._SSR_HYDRATED_DATA\\s*=\\s*(\\{.+?\\})\\s*;?\\s*$/s);
174→                                        if (match) return { method: 'SSR', data: match[1] };
175→                                    }
176→                                }
177→
178→                                // 方法3: 直接找 video 标签
179→                                var video = document.querySelector('video source');
180→                                if (video && video.src) {
181→                                    return { method: 'video_tag', videoUrl: video.src, title: document.title };
182→                                }
183→                                var videoEl = document.querySelector('video');
184→                                if (videoEl && videoEl.src) {
185→                                    return { method: 'video_tag', videoUrl: videoEl.src, title: document.title };
186→                                }
187→
188→                                return { method: 'none', html: document.title };
189→                            } catch(e) {
190→                                return { method: 'error', error: e.message };
191→                            }
192→                        })()
193→                    `);
194→
195→                    clearTimeout(timeout);
196→                    win.destroy();
197→                    resolve(data);
198→                } catch (err) {
199→                    clearTimeout(timeout);
200→                    win.destroy();
201→                    reject(err);
202→                }
203→            }, 3000);
204→        });
205→
206→        win.loadURL(url).catch(err => {
207→            clearTimeout(timeout);
208→            win.destroy();
209→            reject(err);
210→        });
211→    });
212→}
