474→function cleanUrl(url) {
475→    const match = url.match(/https?:\/\/[^\s"'<>]+/);
476→    return match ? match[0] : url.trim();
477→}
478→
479→ipcMain.handle('extract-info', async (event, url) => {
480→    url = cleanUrl(url);
481→    const platform = detectPlatform(url);
482→    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };
483→
484→    if (platform === 'douyin') {
485→        return await extractDouyinInfo(url);
486→    }
487→    return await extractYtdlpInfo(url, platform);
488→});
489→
490→ipcMain.handle('start-download', async (event, url, mode) => {
491→    url = cleanUrl(url);
492→    const platform = detectPlatform(url);
493→    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };
494→
495→    if (platform === 'douyin') {
496→        // 先提取视频信息获取下载链接
497→        const info = await extractDouyinInfo(url);
498→        if (!info.success || !info._videoUrl) {
499→            return { success: false, error: info.error || '无法获取抖音视频下载链接' };
500→        }
501→        return await downloadDouyinVideo(info._videoUrl, info._title);
502→    }
503→    return await downloadYtdlp(url, mode, platform);
504→});
505→
506→ipcMain.handle('refresh-cookies', async () => {
507→    try {
508→        await warmupCookies();
509→        return { success: true };
510→    } catch (err) {
511→        return { success: false, error: err.message };
512→    }
513→});
514→
515→// ============= 工具函数 =============
516→
517→function formatDuration(seconds) {
518→    if (!seconds) return 'N/A';
519→    const hours = Math.floor(seconds / 3600);
520→    const minutes = Math.floor((seconds % 3600) / 60);
521→    const secs = Math.floor(seconds % 60);
522→    if (hours > 0) {
523→        return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
524→    }
525→    return `${minutes}:${secs.toString().padStart(2, '0')}`;
526→}
527→
528→function formatViews(count) {
529→    if (!count) return 'N/A';
530→    if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
531→    if (count >= 1000) return `${(count / 1000).toFixed(1)}K`;
532→    return String(count);
533→}
