}

async function downloadYtdlp(url, mode, platform) {
    return new Promise((resolve) => {
        const outputDir = getDesktopPath();
        const outputTemplate = path.join(outputDir, '%(title)s.%(ext)s');
        let args = [...baseArgs(platform), '--no-playlist'];

        if (mode === 'audio') {
            args.push('-f', 'bestaudio', '-x', '--audio-format', 'mp3', '-o', outputTemplate, url);
        } else if (mode === 'video') {
            args.push('-f', 'bestvideo', '-o', outputTemplate, url);
        } else {
            args.push('-f', 'bestvideo+bestaudio/best', '--merge-output-format', 'mp4', '-o', outputTemplate, url);
        }

        const proc = spawn(getYtdlp(), args);
        let stderr = '';
        let streamCount = 0;
        let maxPercent = 0;

        proc.stdout.on('data', (data) => {
            const output = data.toString();
            if (output.includes('Destination:')) {
                streamCount++;
            }
            // 提取最后一个百分比（一次 data 可能包含多个）
            const matches = output.match(/(\d+\.?\d*)%/g);
            if (matches) {
                const lastMatch = matches[matches.length - 1];
                let percent = parseFloat(lastMatch);
                // 双流下载时：第一个流 0-50%，第二个流 50-100%
                if (streamCount >= 2) {
                    percent = 50 + percent / 2;
                } else if (streamCount === 1 && mode !== 'audio' && mode !== 'video') {
                    percent = percent / 2;
                }
                if (percent > maxPercent) {
                    maxPercent = percent;
                    mainWindow.webContents.send('download-progress', { percent: maxPercent });
                }
            }
            if (output.includes('Merging') || output.includes('[Merger]')) {
                maxPercent = 99;
                mainWindow.webContents.send('download-progress', { percent: 99 });
            }
        });

        proc.stderr.on('data', (data) => { stderr += data.toString(); });

        proc.on('close', (code) => {
            resolve(code === 0 ? { success: true } : { success: false, error: stderr || '下载失败' });
        });

        proc.on('error', () => {
            resolve({ success: false, error: 'yt-dlp 未安装，请先安装 yt-dlp' });
        });
    });
}

// ============= IPC 接口 =============

function cleanUrl(url) {
    const match = url.match(/https?:\/\/[^\s"'<>]+/);
    return match ? match[0] : url.trim();
}

ipcMain.handle('extract-info', async (event, url) => {
    url = cleanUrl(url);
    const platform = detectPlatform(url);
    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };

    if (platform === 'douyin') {
        return await extractDouyinInfo(url);
    }
    return await extractYtdlpInfo(url, platform);
});

ipcMain.handle('start-download', async (event, url, mode) => {
    url = cleanUrl(url);
    const platform = detectPlatform(url);
    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };

    if (platform === 'douyin') {
        // 先提取视频信息获取下载链接
        const info = await extractDouyinInfo(url);
        if (!info.success || !info._videoUrl) {
            return { success: false, error: info.error || '无法获取抖音视频下载链接' };
        }
        return await downloadDouyinVideo(info._videoUrl, info._title);
    }
    return await downloadYtdlp(url, mode, platform);
});

ipcMain.handle('refresh-cookies', async () => {
    try {
        await warmupCookies();
        return { success: true };
    } catch (err) {
        return { success: false, error: err.message };
    }
});

// ============= 工具函数 =============

function formatDuration(seconds) {
    if (!seconds) return 'N/A';
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = Math.floor(seconds % 60);
    if (hours > 0) {
        return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    }
    return `${minutes}:${secs.toString().padStart(2, '0')}`;
}

function formatViews(count) {
    if (!count) return 'N/A';
    if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
    if (count >= 1000) return `${(count / 1000).toFixed(1)}K`;
    return String(count);
}

#!/usr/bin/env python3
"""
Douyin video downloader using yt-dlp with F2 library support.
Outputs JSON for IPC communication with Electron.
"""

import sys
import json
import os
from pathlib import Path

try:
    import yt_dlp
except ImportError:
    print(json.dumps({
        "success": False,
        "error": "yt-dlp Python module not installed. Run: pip install yt-dlp"
    }))
    sys.exit(1)


class DouyinDownloader:
    """Handle Douyin video downloads with progress tracking"""

    def __init__(self, url, output_dir=None):
        self.url = url
        self.output_dir = output_dir or str(Path.home() / "Desktop")
        self.info = None
        self.progress = 0

    def extract_info(self):
        """Extract video information without downloading"""
        try:
            ydl_opts = {
                'quiet': True,
                'no_warnings': True,
                'dump_single_json': True,
                'extract_flat': False,
            }

            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                self.info = ydl.extract_info(self.url, download=False)

            if not self.info:
                return {"success": False, "error": "Failed to extract video info"}

            # Format the response
            response = {
                "success": True,
                "info": self._format_info()
            }
            return response

        except Exception as e:
            return {
                "success": False,
                "error": f"Extraction failed: {str(e)}"
            }

    def download(self, mode='video'):
        """
        Download the video with progress tracking.
        Mode: 'video', 'audio', or 'both'
        """
        try:
            # Determine format based on mode
            if mode == 'audio':
                format_selector = 'bestaudio/best'
                postprocessors = [{
                    'key': 'FFmpegExtractAudio',
                    'preferredcodec': 'mp3',
                    'preferredquality': '192',
                }]
                ext = 'mp3'
            elif mode == 'video':
                format_selector = 'bestvideo[ext=mp4]+bestaudio[ext=m4a]/best[ext=mp4]/best'
                postprocessors = []
                ext = 'mp4'
            else:  # both
                format_selector = 'bestvideo+bestaudio/best'
                postprocessors = [{'key': 'FFmpegVideoConverter', 'preferedformat': 'mp4'}]
                ext = 'mp4'

            # Progress callback
            def progress_hook(d):
                if d['status'] == 'downloading':
                    try:
                        self.progress = d.get('downloaded_bytes', 0) / d.get('total_bytes', 1) * 100
                        # Send progress to stdout as JSON
                        print(json.dumps({
                            "type": "progress",
                            "percent": round(self.progress, 2),
                            "speed": d.get('speed', 0),
                            "eta": d.get('eta', 0)
                        }), flush=True)
                    except (ZeroDivisionError, KeyError):
                        pass
                elif d['status'] == 'finished':
                    print(json.dumps({
                        "type": "progress",
                        "percent": 100,
                        "status": "converting"
                    }), flush=True)

            ydl_opts = {
                'format': format_selector,
                'outtmpl': os.path.join(self.output_dir, '%(title)s.%(ext)s'),
                'progress_hooks': [progress_hook],
                'quiet': True,
                'no_warnings': True,
                'postprocessors': postprocessors if mode != 'video' else [],
            }

            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                ydl.download([self.url])

            return {
                "success": True,
                "message": "Download completed successfully"
            }

        except Exception as e:
            return {
                "success": False,
                "error": f"Download failed: {str(e)}"
            }

    def _format_info(self):
        """Format extracted info for display"""
        if not self.info:
            return {}

        info_dict = {
            "title": self.info.get('title', 'N/A'),
            "description": self.info.get('description', '')[:200],
            "uploader": self.info.get('uploader') or self.info.get('channel', 'N/A'),
            "duration": self.info.get('duration'),
            "view_count": self.info.get('view_count'),
            "like_count": self.info.get('like_count'),
            "upload_date": self.info.get('upload_date', '')[:10] if self.info.get('upload_date') else 'N/A',
            "webpage_url": self.info.get('webpage_url', self.url),
            "thumbnail": self.info.get('thumbnail', ''),
            "platform": 'Douyin'
        }

        return info_dict


def main():
    """CLI entry point"""
    if len(sys.argv) < 2:
        print(json.dumps({
            "success": False,
            "error": "Usage: python douyin_downloader.py <url> [mode] [output_dir]"
        }))
        sys.exit(1)

    url = sys.argv[1]
    mode = sys.argv[2] if len(sys.argv) > 2 else 'info'
    output_dir = sys.argv[3] if len(sys.argv) > 3 else None

    downloader = DouyinDownloader(url, output_dir)

    if mode == 'info':
        result = downloader.extract_info()
    elif mode in ['video', 'audio', 'both']:
        result = downloader.download(mode)
    else:
        result = {"success": False, "error": f"Unknown mode: {mode}"}

    print(json.dumps(result))
    sys.exit(0 if result.get('success') else 1)


if __name__ == '__main__':
    main()

