 328→// 在线例句 (多语种)
 329→ipcMain.handle('fetch-examples', (_, word, lang) => {
 330→  if (lang === 'ja') {
 331→    // 日语: jisho.org API
 332→    return new Promise((resolve) => {
 333→      const url = `https://jisho.org/api/v1/search/words?keyword=${encodeURIComponent(word)}`;
 334→      https.get(url, (res) => {
 335→        let data = '';
 336→        res.on('data', d => data += d);
 337→        res.on('end', () => {
 338→          try {
 339→            const json = JSON.parse(data);
 340→            const entry = json.data?.[0];
 341→            if (!entry) { resolve(null); return; }
 342→            const reading = entry.japanese?.[0]?.reading || '';
 343→            const definitions = (entry.senses || []).slice(0, 5).map(s => ({
 344→              partOfSpeech: (s.parts_of_speech || []).join(', '),
 345→              definition: (s.english_definitions || []).join('; ')
 346→            }));
 347→            resolve({ phonetic: reading, definitions, examples: [] });
 348→          } catch(e) { resolve(null); }
 349→        });
 350→      }).on('error', () => resolve(null));
 351→    });
 352→  }
 353→  // 英语: dictionaryapi.dev
 354→  return new Promise((resolve) => {
 355→    const apiLang = lang === 'en' || !lang ? 'en' : lang;
 356→    const url = `https://api.dictionaryapi.dev/api/v2/entries/${apiLang}/${encodeURIComponent(word)}`;
 357→    https.get(url, (res) => {
 358→      let data = '';
 359→      res.on('data', d => data += d);
 360→      res.on('end', () => {
 361→        try {
 362→          const json = JSON.parse(data);
 363→          if (!Array.isArray(json)) { resolve(null); return; }
 364→          const entry = json[0], examples = [], definitions = [];
 365→          for (const meaning of (entry.meanings || [])) {
 366→            for (const def of (meaning.definitions || [])) {
 367→              definitions.push({ partOfSpeech: meaning.partOfSpeech, definition: def.definition });
 368→              if (def.example) examples.push(def.example);
 369→            }
 370→          }
 371→          resolve({
 372→            phonetic: entry.phonetic || '',
 373→            audio: entry.phonetics?.find(p => p.audio)?.audio || '',
 374→            definitions: definitions.slice(0, 5),
 375→            examples: examples.slice(0, 5)
 376→          });
 377→        } catch(e) { resolve(null); }
 378→      });
 379→    }).on('error', () => resolve(null));
 380→  });
 381→});
