 681→// 通过Python调用Groq Whisper（绕过Node.js https被Groq拒绝的问题）
 682→function transcribeGroqPython(audioPath, lang) {
 683→  return new Promise((resolve) => {
 684→    const tc = loadTranslateConfig();
 685→    const aiCfg = loadAIConfig();
 686→    const groqKey = aiCfg.groqWhisperKey || tc.groq_key || (aiCfg.provider === 'groq' ? aiCfg.apiKey : '');
 687→    if (!groqKey) { resolve(null); return; }
 688→    const wModel = aiCfg.whisperModel || 'whisper-large-v3';
 689→    const langArg = lang || '';
 690→    const script = `
 691→import sys, json, requests, pathlib
 692→f = pathlib.Path(sys.argv[1])
 693→key = sys.argv[2]
 694→lang = sys.argv[3] if len(sys.argv) > 3 and sys.argv[3] else None
 695→wmodel = sys.argv[4] if len(sys.argv) > 4 and sys.argv[4] else "whisper-large-v3"
 696→data = {"model": wmodel, "response_format": "verbose_json", "timestamp_granularities[]": ["word", "segment"], "temperature": "0"}
 697→if lang:
 698→    data["language"] = lang
 699→data["prompt"] = "Transcribe accurately with proper punctuation and capitalization."
 700→with open(f, "rb") as fh:
 701→    r = requests.post("https://api.groq.com/openai/v1/audio/transcriptions",
 702→        headers={"Authorization": f"Bearer {key}"},
 703→        files={"file": (f.name, fh, "application/octet-stream")},
 704→        data=data, timeout=300)
 705→if r.status_code == 200:
 706→    j = r.json()
 707→    words = j.get("words", [])
 708→    segs = j.get("segments", [])
 709→    if words:
 710→        wt = [{"w": w.get("word",""), "s": round(w.get("start",0)*1000), "e": round(w.get("end",0)*1000)} for w in words]
 711→        print(json.dumps({"success": True, "text": j.get("text",""), "words": wt, "timestamp": [[w["s"], w["e"]] for w in wt], "detectedLang": j.get("language","")}))
 712→    else:
 713→        ts = [[int(s.get("start",0)*1000), int(s.get("end",0)*1000)] for s in segs]
 714→        print(json.dumps({"success": True, "text": j.get("text",""), "words": [], "timestamp": ts, "detectedLang": j.get("language","")}))
 715→else:
 716→    print(json.dumps({"success": False, "error": r.text[:200]}))
 717→`;
 718→    const p = spawn('python', ['-c', script, audioPath, groqKey, langArg, wModel]);
 719→    let out = '';
 720→    p.stdout.on('data', d => out += d);
 721→    p.stderr.on('data', () => {});
 722→    p.on('close', () => {
 723→      try { resolve(JSON.parse(out)); } catch(e) { resolve(null); }
 724→    });
 725→    p.on('error', () => resolve(null));
 726→  });
 727→}
