package com.multilanglearner.data.network

import android.util.Log
import com.multilanglearner.domain.model.AIConfig
import com.multilanglearner.domain.model.WordTimestamp
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.*
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.RequestBody.Companion.asRequestBody
import okhttp3.RequestBody.Companion.toRequestBody
import java.io.File
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

@Serializable
data class WhisperResult(
    val success: Boolean,
    val text: String = "",
    val words: List<WordTimestamp> = emptyList(),
    val detectedLang: String = "",
    val error: String = ""
)

@Singleton
class WhisperService @Inject constructor() {
    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(300, TimeUnit.SECONDS)
        .writeTimeout(60, TimeUnit.SECONDS)
        .build()

    private val json = Json { ignoreUnknownKeys = true }

    // Groq API 文件大小限制（25MB）
    private val MAX_FILE_SIZE = 25 * 1024 * 1024L

    /**
     * Transcribe audio via Groq Whisper API
     * 优先使用 groqApiKey，其次使用 provider 为 groq 时的 apiKey
     */
    suspend fun transcribeGroq(audioFile: File, config: AIConfig, lang: String? = null): WhisperResult? {
        // 获取 Groq API Key：优先使用专门的 groqApiKey，其次检查 provider 是否为 groq
        val apiKey = config.groqApiKey.takeIf { it.isNotBlank() }
            ?: (config.apiKey.takeIf { config.provider == "groq" && it.isNotBlank() })
            ?: return WhisperResult(success = false, error = "未配置 Groq API Key，请在设置中添加")

        val whisperModel = config.whisperModel.ifBlank { "whisper-large-v3" }

        // 检查文件大小
        val fileSize = audioFile.length()
        Log.d("WhisperService", "File size: $fileSize bytes, max: $MAX_FILE_SIZE")

        if (fileSize > MAX_FILE_SIZE) {
            val sizeMB = String.format("%.2f", fileSize / 1024.0 / 1024.0)
            val maxMB = String.format("%.2f", MAX_FILE_SIZE / 1024.0 / 1024.0)
            Log.e("WhisperService", "File too large: $sizeMB MB (max: $maxMB MB)")
            return WhisperResult(
                success = false,
                error = "文件太大 ($sizeMB MB)，超过 Groq 限制 ($maxMB MB)。请先在电脑上使用 yt-dlp 下载视频并提取音频，或使用较短的视频。"
            )
        }

        Log.d("WhisperService", "Starting transcription with Groq Whisper: model=$whisperModel, file=${audioFile.name}, size=$fileSize")

        val bodyBuilder = MultipartBody.Builder().setType(MultipartBody.FORM)
            .addFormDataPart("file", audioFile.name, audioFile.asRequestBody("application/octet-stream".toMediaType()))
            .addFormDataPart("model", whisperModel)
            .addFormDataPart("response_format", "verbose_json")
            .addFormDataPart("timestamp_granularities[]", "word")
            .addFormDataPart("timestamp_granularities[]", "segment")
            .addFormDataPart("temperature", "0")
            .addFormDataPart("prompt", "Transcribe accurately with proper punctuation and capitalization.")

        lang?.let { bodyBuilder.addFormDataPart("language", it) }

        val request = Request.Builder()
            .url("https://api.groq.com/openai/v1/audio/transcriptions")
            .addHeader("Authorization", "Bearer $apiKey")
            .post(bodyBuilder.build())
            .build()

        return try {
            Log.d("WhisperService", "Sending request to Groq API...")
            val response = client.newCall(request).execute()

            Log.d("WhisperService", "Response code: ${response.code}")

            if (response.code != 200) {
                val errorBody = response.body?.string() ?: "Unknown error"
                Log.e("WhisperService", "API error: $errorBody")

                // 解析错误信息
                val errorMsg = try {
                    val errorJson = json.parseToJsonElement(errorBody).jsonObject
                    errorJson["error"]?.jsonObject?.get("message")?.jsonPrimitive?.contentOrNull
                        ?: errorJson["error"]?.jsonObject?.get("type")?.jsonPrimitive?.contentOrNull
                        ?: errorBody
                } catch (e: Exception) {
                    errorBody
                }

                return WhisperResult(success = false, error = "转录失败: $errorMsg")
            }

            val body = response.body?.string() ?: return WhisperResult(success = false, error = "空响应")
            Log.d("WhisperService", "Response length: ${body.length}")

            val jsonObj = json.parseToJsonElement(body).jsonObject
            val text = jsonObj["text"]?.jsonPrimitive?.contentOrNull ?: ""
            val detectedLang = jsonObj["language"]?.jsonPrimitive?.contentOrNull ?: ""

            Log.d("WhisperService", "Transcribed text length: ${text.length}, detected language: $detectedLang")

            val words = jsonObj["words"]?.jsonArray?.map { w ->
                val obj = w.jsonObject
                WordTimestamp(
                    w = obj["word"]?.jsonPrimitive?.contentOrNull ?: "",
                    s = (obj["start"]?.jsonPrimitive?.doubleOrNull ?: 0.0),
                    e = (obj["end"]?.jsonPrimitive?.doubleOrNull ?: 0.0)
                )
            } ?: emptyList()

            Log.d("WhisperService", "Word timestamps count: ${words.size}")

            WhisperResult(success = true, text = text, words = words, detectedLang = detectedLang)
        } catch (e: Exception) {
            Log.e("WhisperService", "Transcription error", e)
            WhisperResult(success = false, error = "网络错误: ${e.message}")
        }
    }
}

package com.multilanglearner.data.network

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.coroutines.withTimeout
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONObject
import java.io.IOException
import java.util.concurrent.TimeUnit

/**
 * 视频下载服务 - 使用在线 API 解析视频
 * 支持多平台：B站、抖音、YouTube 等
 */
class VideoDownloadService {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .followRedirects(false)
        .build()

    /**
     * 平台检测
     */
    fun detectPlatform(url: String): VideoPlatform {
        val lowerUrl = url.lowercase()
        return when {
            lowerUrl.contains("bilibili.com") || lowerUrl.contains("b23.tv") -> VideoPlatform.BILIBILI
            lowerUrl.contains("douyin.com") || lowerUrl.contains("iesdouyin.com") -> VideoPlatform.DOUYIN
            lowerUrl.contains("tiktok.com") -> VideoPlatform.TIKTOK
            lowerUrl.contains("youtube.com") || lowerUrl.contains("youtu.be") -> VideoPlatform.YOUTUBE
            lowerUrl.contains("weibo.com") -> VideoPlatform.WEIBO
            lowerUrl.contains("xiaohongshu.com") || lowerUrl.contains("xhslink.com") -> VideoPlatform.XIAOHONGSHU
            lowerUrl.contains(".mp4") || lowerUrl.contains(".m3u8") -> VideoPlatform.DIRECT
            else -> VideoPlatform.UNKNOWN
        }
    }

    /**
     * 获取视频下载链接
     */
    suspend fun getVideoInfo(url: String): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        withTimeout(30_000) {
            try {
                val platform = detectPlatform(url)
                Log.d("VideoDownloadService", "Platform: $platform, URL: $url")

                when (platform) {
                    VideoPlatform.BILIBILI -> fetchBilibiliInfo(url)
                    VideoPlatform.DOUYIN -> fetchDouyinInfo(url)
                    VideoPlatform.TIKTOK -> fetchTiktokInfo(url)
                    VideoPlatform.DIRECT -> Result.success(VideoDownloadInfo("视频", url, null, 0L, null))
                    else -> Result.failure(Exception("不支持的平台，请使用导入功能"))
                }
            } catch (e: Exception) {
                Log.e("VideoDownloadService", "Error fetching video info", e)
                Result.failure(e)
            }
        }
    }

    /**
     * 获取 B站视频信息 - 使用多个备用API
     */
    private suspend fun fetchBilibiliInfo(url: String): Result<VideoDownloadInfo> {
        // 尝试多个API（按优先级排序）
        val apis = listOf(
            // API 1: xboba (稳定)
            "https://api.xboba.com/bilibili/video/download?url=$url",
            // API 2: 805t (备用)
            "https://api.805t.cn/bilibili/api?url=$url",
            // API 3: yl (备用)
            "https://api.y1les.cn/api/bilibili?url=$url",
            // API 4: xingzhige (备用)
            "https://api.xingzhige.com/API/BiliBili/downUrl?url=$url"
        )

        for (apiUrl in apis) {
            try {
                Log.d("VideoDownloadService", "Trying API: $apiUrl")
                val request = Request.Builder()
                    .url(apiUrl)
                    .header("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64)")
                    .build()

                val response = client.newCall(request).execute()
                val responseBody = response.body?.string() ?: continue

                Log.d("VideoDownloadService", "Response: ${responseBody.take(200)}")

                // 检查是否是HTML
                if (responseBody.trim().startsWith("<!DOCTYPE") || responseBody.trim().startsWith("<html")) {
                    Log.d("VideoDownloadService", "API returned HTML, skipping")
                    continue
                }

                val json = JSONObject(responseBody)

                // 尝试解析返回数据 - 支持多种API格式
                // 格式1: {data: {url: "...", title: "..."}}
                if (json.has("data")) {
                    val data = json.getJSONObject("data")
                    val videoUrl = data.optJSONArray("url")?.optString(0)
                        ?: data.optString("url")
                        ?: data.optString("video_url")
                        ?: data.optString("playurl")
                    val title = data.optString("title")
                        ?: data.optString("name")
                        ?: "B站视频"

                    if (videoUrl.isNotEmpty() && videoUrl.startsWith("http")) {
                        Log.d("VideoDownloadService", "Got video URL: $videoUrl")
                        return Result.success(VideoDownloadInfo(
                            title = title,
                            downloadUrl = videoUrl,
                            cover = data.optString("pic")
                                ?: data.optString("cover")
                                ?: data.optString("img"),
                            duration = data.optLong("duration", 0L) / 1000,
                            author = data.optString("author")
                                ?: data.optString("uploader")
                        ))
                    }
                }

                // 格式2: {url: "...", title: "..."}
                val directUrl = json.optString("url")
                    ?: json.optString("video_url")
                    ?: json.optString("playurl")
                if (directUrl.startsWith("http")) {
                    val title = json.optString("title") ?: "B站视频"
                    Log.d("VideoDownloadService", "Got direct URL: $directUrl")
                    return Result.success(VideoDownloadInfo(
                        title = title,
                        downloadUrl = directUrl,
                        cover = json.optString("pic") ?: json.optString("cover"),
                        duration = json.optLong("duration", 0L) / 1000
                    ))
                }

                // 格式3: {code: 200, data: {url: "..."}} 或 {code: 200, url: "..."}
                if (json.optInt("code") == 200) {
                    val videoUrl = json.optJSONObject("data")?.optString("url")
                        ?: json.optString("url")
                        ?: json.optString("video_url")
                    if (videoUrl?.startsWith("http") == true) {
                        val title = json.optJSONObject("data")?.optString("title")
                            ?: json.optString("title")
                            ?: "B站视频"
                        return Result.success(VideoDownloadInfo(
                            title = title,
                            downloadUrl = videoUrl
                        ))
                    }
                }
            } catch (e: Exception) {
                Log.e("VideoDownloadService", "API failed: $apiUrl", e)
            }
        }

        return Result.failure<VideoDownloadInfo>(Exception("B站API全部失效，请使用导入功能"))
    }

    /**
     * 获取抖音视频信息
     */
    private suspend fun fetchDouyinInfo(url: String): Result<VideoDownloadInfo> {
        return try {
            val apiUrl = "https://api.pearktrue.com/api/v1/parse/douyin?url=$url"

            val request = Request.Builder()
                .url(apiUrl)
                .header("User-Agent", "Mozilla/5.0")
                .build()

            val response = client.newCall(request).execute()
            val responseBody = response.body?.string() ?: return Result.failure(IOException("空响应"))

            val json = JSONObject(responseBody)
            if (json.optInt("code") == 200 && json.has("data")) {
                val data = json.getJSONObject("data")
                val videoData = data.optJSONArray("video")?.optJSONObject(0)
                    ?: data

                Result.success(VideoDownloadInfo(
                    title = data.optString("desc", data.optString("title", "抖音视频")),
                    downloadUrl = videoData.optString("play_addr", videoData.optString("url")),
                    cover = data.optString("cover", data.optString("thumb")),
                    author = data.optJSONObject("author")?.optString("nickname")
                ))
            } else {
                Result.failure(Exception("解析失败"))
            }
        } catch (e: Exception) {
            Result.failure(Exception("抖音解析失败: ${e.message}"))
        }
    }

    /**
     * 获取 TikTok 视频信息
     */
    private suspend fun fetchTiktokInfo(url: String): Result<VideoDownloadInfo> {
        return try {
            fetchDouyinInfo(url)
        } catch (e: Exception) {
            Result.failure(Exception("TikTok 解析失败"))
        }
    }

    /**
     * 下载数据类
     */
    data class VideoDownloadInfo(
        val title: String,
        val downloadUrl: String,
        val cover: String? = null,
        val duration: Long = 0,
        val author: String? = null
    )

    /**
     * 支持的平台
     */
    enum class VideoPlatform {
        BILIBILI, DOUYIN, TIKTOK, YOUTUBE, WEIBO, XIAOHONGSHU, DIRECT, UNKNOWN
    }
}

package com.multilanglearner.data.network

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import java.io.File
import java.io.IOException
import java.io.RandomAccessFile
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 分段下载管理器
 * 支持大文件分段下载和断点续传
 */
@Singleton
class SegmentedDownloader @Inject constructor() {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    // 每个分段的大小（5MB）
    private val SEGMENT_SIZE = 5L * 1024 * 1024

    // 最小分段大小（1MB，小于此文件不分段）
    private val MIN_SEGMENT_SIZE = 1L * 1024 * 1024

    /**
     * 下载进度回调
     */
    data class DownloadProgress(
        val bytesDownloaded: Long,
        val totalBytes: Long,
        val percent: Int,
        val speed: Long, // bytes per second
        val segmentIndex: Int,
        val totalSegments: Int
    )

    /**
     * 下载配置
     */
    data class DownloadConfig(
        val url: String,
        val outputFile: File,
        val segmentSize: Long = SEGMENT_SIZE,
        val enableResume: Boolean = true,
        val onProgress: (DownloadProgress) -> Unit = {}
    )

    /**
     * 开始分段下载
     */
    suspend fun download(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        try {
            Log.d("SegmentedDownloader", "Starting download: ${config.url}")

            // 获取文件大小
            val fileSize = getContentLength(config.url)
            if (fileSize <= 0) {
                // 不支持分段下载，使用普通下载
                Log.d("SegmentedDownloader", "Segmented download not supported, using simple download")
                return@withContext simpleDownload(config)
            }

            Log.d("SegmentedDownloader", "File size: $fileSize bytes")

            // 判断是否需要分段
            if (fileSize < MIN_SEGMENT_SIZE) {
                Log.d("SegmentedDownloader", "File too small for segmentation, using simple download")
                return@withContext simpleDownload(config)
            }

            // 计算分段数量
            val segmentCount = ((fileSize + config.segmentSize - 1) / config.segmentSize).toInt()
            Log.d("SegmentedDownloader", "Splitting into $segmentCount segments")

            // 创建临时文件
            val tempFile = File(config.outputFile.absolutePath + ".tmp")
            val raf = RandomAccessFile(tempFile, "rw")
            raf.setLength(fileSize)

            // 下载每个分段
            val downloadedSegments = if (config.enableResume) {
                loadResumeState(tempFile)
            } else {
                mutableSetOf()
            }

            var totalDownloaded = 0L
            val startTime = System.currentTimeMillis()

            for (i in 0 until segmentCount) {
                if (i in downloadedSegments) {
                    Log.d("SegmentedDownloader", "Segment $i already downloaded, skipping")
                    totalDownloaded += minOf(config.segmentSize, fileSize - i * config.segmentSize)
                    continue
                }

                val start = i * config.segmentSize
                val end = minOf(start + config.segmentSize - 1, fileSize - 1)

                Log.d("SegmentedDownloader", "Downloading segment $i: $start-$end")

                try {
                    downloadSegment(config.url, tempFile, start, end) { bytes ->
                        totalDownloaded += bytes
                        val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                        val speed = if (elapsed > 0) totalDownloaded / elapsed.toLong() else 0

                        config.onProgress(DownloadProgress(
                            bytesDownloaded = totalDownloaded,
                            totalBytes = fileSize,
                            percent = ((totalDownloaded * 100) / fileSize).toInt(),
                            speed = speed,
                            segmentIndex = i + 1,
                            totalSegments = segmentCount
                        ))
                    }

                    downloadedSegments.add(i)
                    saveResumeState(tempFile, downloadedSegments)
                } catch (e: Exception) {
                    Log.e("SegmentedDownloader", "Failed to download segment $i", e)
                    raf.close()
                    // 保存断点信息
                    saveResumeState(tempFile, downloadedSegments)
                    throw e
                }
            }

            raf.close()

            // 重命名为最终文件
            if (config.outputFile.exists()) {
                config.outputFile.delete()
            }
            tempFile.renameTo(config.outputFile)

            Log.d("SegmentedDownloader", "Download completed: ${config.outputFile.absolutePath}")
            Result.success(config.outputFile)
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Download failed", e)
            Result.failure(e)
        }
    }

    /**
     * 简单下载（不支持分段）
     */
    private suspend fun simpleDownload(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        try {
            val request = okhttp3.Request.Builder()
                .url(config.url)
                .build()

            val response = client.newCall(request).execute()

            if (!response.isSuccessful) {
                throw IOException("HTTP ${response.code}")
            }

            val body = response.body ?: throw IOException("No response body")
            val inputStream = body.byteStream()
            val totalBytes = body.contentLength()
            var downloadedBytes = 0L
            val startTime = System.currentTimeMillis()

            config.outputFile.outputStream().use { output ->
                val buffer = ByteArray(8 * 1024)
                var bytes: Int

                while (inputStream.read(buffer).also { bytes = it } > 0) {
                    output.write(buffer, 0, bytes)
                    downloadedBytes += bytes

                    val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                    val speed = if (elapsed > 0) (downloadedBytes / elapsed).toLong() else 0

                    if (totalBytes > 0) {
                        config.onProgress(DownloadProgress(
                            bytesDownloaded = downloadedBytes,
                            totalBytes = totalBytes,
                            percent = ((downloadedBytes * 100) / totalBytes).toInt(),
                            speed = speed,
                            segmentIndex = 1,
                            totalSegments = 1
                        ))
                    }
                }
            }

            Result.success(config.outputFile)
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Simple download failed", e)
            Result.failure(e)
        }
    }

    /**
     * 下载单个分段
     */
    private fun downloadSegment(
        url: String,
        file: File,
        start: Long,
        end: Long,
        onBytesDownloaded: (Long) -> Unit
    ) {
        val request = okhttp3.Request.Builder()
            .url(url)
            .header("Range", "bytes=$start-$end")
            .build()

        val response = client.newCall(request).execute()

        if (response.code !in 200..299) {
            throw IOException("HTTP ${response.code} for segment $start-$end")
        }

        val inputStream = response.body?.byteStream() ?: throw IOException("No response body")
        val raf = RandomAccessFile(file, "rw")
        raf.seek(start)

        val buffer = ByteArray(8 * 1024)
        var bytes: Int
        var totalBytes = 0L

        while (inputStream.read(buffer).also { bytes = it } > 0) {
            raf.write(buffer, 0, bytes)
            totalBytes += bytes
            onBytesDownloaded(bytes.toLong())
        }

        raf.close()
        inputStream.close()
    }

    /**
     * 获取文件内容长度
     */
    private fun getContentLength(url: String): Long {
        return try {
            val request = okhttp3.Request.Builder()
                .url(url)
                .head()
                .build()

            val response = client.newCall(request).execute()

            // 检查是否支持断点续传
            val acceptRanges = response.header("Accept-Ranges") == "bytes"
            val contentLength = response.body?.contentLength() ?: 0

            if (acceptRanges && contentLength > 0) {
                contentLength
            } else {
                0
            }
        } catch (e: Exception) {
            Log.w("SegmentedDownloader", "Failed to get content length", e)
            0
        }
    }

    /**
     * 保存断点状态
     */
    private fun saveResumeState(file: File, segments: Set<Int>) {
        try {
            val stateFile = File(file.absolutePath + ".resume")
            stateFile.writeText(segments.joinToString(","))
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to save resume state", e)
        }
    }

    /**
     * 加载断点状态
     */
    private fun loadResumeState(file: File): MutableSet<Int> {
        return try {
            val stateFile = File(file.absolutePath + ".resume")
            if (stateFile.exists()) {
                val content = stateFile.readText()
                if (content.isNotBlank()) {
                    content.split(",").mapNotNull { it.toIntOrNull() }.toMutableSet()
                } else {
                    mutableSetOf()
                }
            } else {
                mutableSetOf()
            }
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to load resume state", e)
            mutableSetOf()
        }
    }

    /**
     * 清理断点状态
     */
    fun clearResumeState(file: File) {
        try {
            val stateFile = File(file.absolutePath + ".resume")
            if (stateFile.exists()) {
                stateFile.delete()
            }
            val tempFile = File(file.absolutePath + ".tmp")
            if (tempFile.exists()) {
                tempFile.delete()
            }
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to clear resume state", e)
        }
    }

    /**
     * 取消下载并清理临时文件
     */
    fun cancelDownload(outputFile: File) {
        clearResumeState(outputFile)
    }
}

