package com.multilanglearner.data.network

import android.content.Context
import android.media.MediaMetadataRetriever
import android.util.Log
import com.multilanglearner.domain.model.AIConfig
import com.multilanglearner.domain.model.WordTimestamp
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import java.io.File
import java.io.FileInputStream
import java.io.FileOutputStream
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 分段转录服务
 * 支持大视频文件分段转录，避免 API 文件大小限制
 *
 * 参考自 Electron 版本的分段转录逻辑：
 * - 将视频按时长分段（默认每10分钟一段）
 * - 提取每段的音频
 * - 使用 Whisper API 转录
 * - 合并所有段落的字幕
 */
@Singleton
class SegmentedTranscribeService @Inject constructor(
    @ApplicationContext private val context: Context,
    private val whisperService: WhisperService
) {
    private val json = Json { ignoreUnknownKeys = true }

    // 每段时长（秒）- 与 Electron 版本保持一致
    private val SEGMENT_DURATION = 600 // 10分钟

    // 前台转录限制（秒）- 前台转录40分钟，剩余后台继续
    private val FOREGROUND_LIMIT = 2400

    // Whisper API 文件大小限制（25MB）
    private val MAX_WHISPER_FILE_SIZE = 25L * 1024 * 1024

    // 临时文件目录
    private val tempDir: File by lazy {
        File(context.cacheDir, "audio_segments").apply {
            if (!exists()) mkdirs()
        }
    }

    /**
     * 转录进度回调
     */
    data class TranscribeProgress(
        val currentSegment: Int,
        val totalSegments: Int,
        val message: String
    )

    /**
     * 转录结果
     */
    @Serializable
    data class TranscribeResult(
        val success: Boolean,
        val text: String = "",
        val words: List<WordTimestamp> = emptyList(),
        val detectedLang: String = "",
        val error: String = ""
    )

    /**
     * 转录视频文件
     * @param videoFile 视频文件
     * @param config AI 配置
     * @param onProgress 进度回调
     */
    suspend fun transcribeVideo(
        videoFile: File,
        config: AIConfig,
        onProgress: (Int, Int, String) -> Unit = { _, _, _ -> }
    ): TranscribeResult = withContext(Dispatchers.IO) {
        try {
            Log.d("SegmentedTranscribe", "Starting video transcription: ${videoFile.name}")

            // 获取视频时长
            val duration = getVideoDuration(videoFile)
            if (duration <= 0) {
                Log.e("SegmentedTranscribe", "Failed to get video duration")
                return@withContext TranscribeResult(
                    success = false,
                    error = "无法获取视频时长"
                )
            }

            val durationMin = (duration / 60).toInt()
            Log.d("SegmentedTranscribe", "Video duration: ${durationMin} minutes")

            // 计算分段数量
            val totalSegments = ((duration + SEGMENT_DURATION - 1) / SEGMENT_DURATION).toInt()
            Log.d("SegmentedTranscribe", "Total segments: $totalSegments")

            // 前台转录段数
            val foregroundSegments = ((minOf(duration, FOREGROUND_LIMIT.toDouble()) + SEGMENT_DURATION - 1) / SEGMENT_DURATION).toInt()
            Log.d("SegmentedTranscribe", "Foreground segments: $foregroundSegments")

            // 转录前台部分
            var allText = ""
            val allWords = mutableListOf<WordTimestamp>()
            var detectedLang = ""

            onProgress(0, totalSegments, "正在分析视频...")

            // 转录指定范围的段落
            fun transcribeRange(startSeg: Int, endSeg: Int): Pair<String, List<WordTimestamp>> {
                var rangeText = ""
                val rangeWords = mutableListOf<WordTimestamp>()

                for (i in startSeg until endSeg) {
                    val segStart = i * SEGMENT_DURATION
                    val progressMsg = "[${i - startSeg + 1}/${endSeg - startSeg}] 提取音频 ${i + 1}/$totalSegments"
                    onProgress(i + 1, totalSegments, progressMsg)
                    Log.d("SegmentedTranscribe", progressMsg)

                    // 提取音频段
                    val audioFile = extractAudioSegment(videoFile, segStart, SEGMENT_DURATION)
                        ?: continue

                    try {
                        val transcribeMsg = "[${i - startSeg + 1}/${endSeg - startSeg}] 转录 ${i + 1}/$totalSegments"
                        onProgress(i + 1, totalSegments, transcribeMsg)
                        Log.d("SegmentedTranscribe", transcribeMsg)

                        // 调用 Whisper API 转录
                        val result = whisperService.transcribeGroq(audioFile, config)

                        if (result != null && result.success) {
                            // 更新检测到的语言
                            if (result.detectedLang.isNotBlank() && detectedLang.isBlank()) {
                                detectedLang = result.detectedLang
                                val langName = getLanguageName(detectedLang)
                                onProgress(i + 1, totalSegments, "$transcribeMsg - 检测到$langName")
                            }

                            // 处理转录结果
                            val segmentText = result.text
                            val segmentWords = result.words

                            if (segmentText.isNotBlank()) {
                                // 添加段落时间偏移
                                val offset = segStart.toDouble()
                                val adjustedWords = segmentWords.map { wt ->
                                    WordTimestamp(
                                        w = wt.w,
                                        s = wt.s + offset,
                                        e = wt.e + offset
                                    )
                                }
                                rangeWords.addAll(adjustedWords)
                                rangeText += segmentText + " "
                            }
                        } else {
                            Log.w("SegmentedTranscribe", "Failed to transcribe segment $i: ${result?.error}")
                        }
                    } finally {
                        // 清理临时音频文件
                        audioFile.delete()
                    }
                }

                return Pair(rangeText.trim(), rangeWords)
            }

            // 前台转录
            onProgress(0, totalSegments, "开始转录...")
            val (fgText, fgWords) = transcribeRange(0, foregroundSegments)
            allText = fgText
            allWords.addAll(fgWords)

            // 立即返回前台结果，后台继续转录
            if (foregroundSegments < totalSegments) {
                onProgress(foregroundSegments, totalSegments, "前 ${FOREGROUND_LIMIT / 60} 分钟字幕已就绪，剩余部分后台转录中...")

                // 启动后台任务
                kotlinx.coroutines.GlobalScope.launch(Dispatchers.IO) {
                    try {
                        val (bgText, bgWords) = transcribeRange(foregroundSegments, totalSegments)

                        // 合并并保存
                        val finalText = allText + " " + bgText
                        val finalWords = allWords + bgWords

                        // 保存字幕文件
                        saveSubtitleFiles(videoFile, finalText, finalWords)

                        Log.d("SegmentedTranscribe", "Background transcription completed")
                    } catch (e: Exception) {
                        Log.e("SegmentedTranscribe", "Background transcription failed", e)
                    }
                }
            } else {
                onProgress(totalSegments, totalSegments, "转录完成，共 $totalSegments 段")
                // 保存字幕文件
                saveSubtitleFiles(videoFile, allText, allWords)
            }

            TranscribeResult(
                success = true,
                text = allText,
                words = allWords,
                detectedLang = detectedLang
            )
        } catch (e: Exception) {
            Log.e("SegmentedTranscribe", "Transcription failed", e)
            TranscribeResult(
                success = false,
                error = "转录失败: ${e.message}"
            )
        }
    }

    /**
     * 提取音频分段
     * 使用 FFmpeg 或 MediaExtractor 提取指定时间范围的音频
     */
    private suspend fun extractAudioSegment(
        videoFile: File,
        startSec: Long,
        durationSec: Int
    ): File? = withContext(Dispatchers.IO) {
        try {
            val outputFile = File(tempDir, "seg_${startSec}_${System.currentTimeMillis()}.wav")

            // 先检查文件大小，如果整个视频的音频部分小于限制，直接复制
            val fileSize = videoFile.length()

            // 简化实现：使用 ffmpeg 命令行（如果可用）
            // 或者使用 Android MediaExtractor API

            // 检查是否有可用的 FFmpeg
            val ffmpegPath = findFFmpeg()
            if (ffmpegPath != null) {
                // 使用 FFmpeg 提取音频
                val process = ProcessBuilder(
                    ffmpegPath,
                    "-y", // 覆盖输出文件
                    "-ss", startSec.toString(), // 开始时间
                    "-t", durationSec.toString(), // 持续时间
                    "-i", videoFile.absolutePath, // 输入文件
                    "-vn", // 不要视频
                    "-ar", "16000", // 采样率 16kHz（Whisper 推荐）
                    "-ac", "1", // 单声道
                    "-f", "wav", // WAV 格式
                    outputFile.absolutePath
                ).redirectErrorStream(true)
                    .start()

                val output = process.inputStream.bufferedReader().readText()
                val exitCode = process.waitFor()

                if (exitCode == 0 && outputFile.exists()) {
                    Log.d("SegmentedTranscribe", "Extracted audio segment: ${outputFile.name}, size: ${outputFile.length()}")
                    return@withContext outputFile
                } else {
                    Log.w("SegmentedTranscribe", "FFmpeg failed: $output")
                }
            }

            // 回退方案：使用 Java 音频处理（较慢但兼容）
            // 这里简化处理，实际项目中可能需要更复杂的实现
            null
        } catch (e: Exception) {
            Log.e("SegmentedTranscribe", "Failed to extract audio segment", e)
            null
        }
    }

    /**
     * 查找 FFmpeg 可执行文件
     */
    private fun findFFmpeg(): String? {
        // 检查常见的 FFmpeg 位置
        val possiblePaths = listOf(
            "/data/data/com.multilanglearner/files/ffmpeg",
            "/system/bin/ffmpeg",
            context.filesDir.absolutePath + "/ffmpeg"
        )

        for (path in possiblePaths) {
            val file = File(path)
            if (file.exists() && file.canExecute()) {
                return path
            }
        }

        return null
    }

    /**
     * 获取视频时长（秒）
     */
    private fun getVideoDuration(videoFile: File): Long {
        val retriever = MediaMetadataRetriever()
        return try {
            retriever.setDataSource(videoFile.absolutePath)
            val timeStr = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DURATION)
            (timeStr?.toLongOrNull() ?: 0) / 1000
        } catch (e: Exception) {
            Log.e("SegmentedTranscribe", "Failed to get video duration", e)
            0
        } finally {
            retriever.release()
        }
    }

    /**
     * 保存字幕文件
     */
    private fun saveSubtitleFiles(videoFile: File, text: String, words: List<WordTimestamp>) {
        try {
            val base = videoFile.absolutePath.substringBeforeLast(".")
            val vttFile = File(base + ".vtt")
            val wtsFile = File(base + ".wordts.json")

            // 生成 VTT 字幕
            val vttBuilder = StringBuilder("WEBVTT\n\n")

            if (words.isNotEmpty()) {
                // 使用单词级时间戳生成句子级字幕
                var curWords = mutableListOf<WordTimestamp>()
                for (wt in words) {
                    curWords.add(wt)
                    // 按句子分隔符切分
                    if (wt.w.trim().matches(Regex(".*[.!?。！？]$")) && curWords.isNotEmpty()) {
                        val sentText = curWords.joinToString(" ") { it.w }
                        val sStart = curWords.first().s
                        val sEnd = curWords.last().e
                        vttBuilder.append("${formatVTT(sStart)} --> ${formatVTT(sEnd)}\n$sentText\n\n")
                        curWords = mutableListOf()
                    }
                }
                // 添加剩余的词
                if (curWords.isNotEmpty()) {
                    val sentText = curWords.joinToString(" ") { it.w }
                    val sStart = curWords.first().s
                    val sEnd = curWords.last().e
                    vttBuilder.append("${formatVTT(sStart)} --> ${formatVTT(sEnd)}\n$sentText\n\n")
                }
            } else {
                // 没有单词级时间戳，使用整段文本
                vttBuilder.append("00:00:00.000 --> 00:00:10.000\n$text\n\n")
            }

            vttFile.writeText(vttBuilder.toString())

            // 保存单词级时间戳
            if (words.isNotEmpty()) {
                wtsFile.writeText(
                    json.encodeToString(
                        kotlinx.serialization.builtins.ListSerializer(WordTimestamp.serializer()),
                        words
                    )
                )
            }

            Log.d("SegmentedTranscribe", "Saved subtitle files: ${vttFile.name}")
        } catch (e: Exception) {
            Log.e("SegmentedTranscribe", "Failed to save subtitle files", e)
        }
    }

    /**
     * 格式化 VTT 时间戳
     */
    private fun formatVTT(seconds: Double): String {
        val hours = (seconds / 3600).toInt()
        val minutes = ((seconds % 3600) / 60).toInt()
        val secs = seconds % 60
        return String.format("%02d:%02d:%06.3f", hours, minutes, secs)
    }

    /**
     * 获取语言名称
     */
    private fun getLanguageName(code: String): String {
        return when (code.lowercase()) {
            "en", "english" -> "英语"
            "ja", "japanese" -> "日语"
            "ko", "korean" -> "韩语"
            "ru", "russian" -> "俄语"
            "th", "thai" -> "泰语"
            "vi", "vietnamese" -> "越南语"
            "ms", "malay" -> "马来语"
            "id", "indonesian" -> "印尼语"
            "ar", "arabic" -> "阿拉伯语"
            "pt", "portuguese" -> "葡萄牙语"
            "es", "spanish" -> "西班牙语"
            "fr", "french" -> "法语"
            "de", "german" -> "德语"
            "hi", "hindi" -> "印地语"
            "zh", "chinese" -> "中文"
            else -> code
        }
    }

    /**
     * 清理临时文件
     */
    fun cleanup() {
        try {
            tempDir.deleteRecursively()
        } catch (e: Exception) {
            Log.e("SegmentedTranscribe", "Failed to cleanup temp dir", e)
        }
    }
}
